/* expat_config.h — hand-written for our freestanding x86_64 environment.
 *
 * Generated by autoconf/CMake in upstream builds; here we hardcode the
 * constants that match our kernel/userspace environment.
 *
 * Copyright (c) 2026 hesse
 * SPDX-License-Identifier: MIT
 */

#ifndef EXPAT_CONFIG_H
#define EXPAT_CONFIG_H 1

/* x86_64 is little-endian */
#define BYTEORDER 1234

/* Standard headers available in our libc */
#define HAVE_FCNTL_H 1
#define HAVE_STDINT_H 1
#define HAVE_STDLIB_H 1
#define HAVE_STRING_H 1
#define HAVE_SYS_TYPES_H 1
#define HAVE_UNISTD_H 1
#define STDC_HEADERS 1

/* Expat feature configuration — enable all standard XML features */
#define XML_CONTEXT_BYTES 1024
#define XML_DTD 1
#define XML_GE 1
#define XML_NS 1

/* Entropy source: /dev/urandom (kernel provides it via devtmpfs) */
#define XML_DEV_URANDOM 1

/* random_dev_urandom.c uses O_CLOEXEC which our <fcntl.h> does not
 * define yet.  Provide a fallback matching Linux x86_64 value. */
#ifndef O_CLOEXEC
#define O_CLOEXEC 02000000
#endif

#endif /* EXPAT_CONFIG_H */
